    94→/**
    95→ * Seed built-in capabilities on activation.
    96→ */
    97→function agentpress_seed_capabilities() {
    98→    $capabilities = array(
    99→        array(
   100→            'slug' => 'content_writer',
   101→            'title' => 'Content Writer',
   102→            'description' => 'Generates written content using Claude API.',
   103→        ),
   104→        array(
   105→            'slug' => 'image_generator',
   106→            'title' => 'Image Generator',
   107→            'description' => 'Generates images using Cloudflare Workers AI.',
   108→        ),
   109→    );
   110→
   111→    foreach ($capabilities as $cap) {
   112→        // Check if capability already exists
   113→        $existing = get_posts(array(
   114→            'post_type' => 'agentpress_capability',
   115→            'name' => $cap['slug'],
   116→            'posts_per_page' => 1,
   117→            'post_status' => 'any',
   118→        ));
   119→
   120→        if (empty($existing)) {
   121→            wp_insert_post(array(
   122→                'post_type' => 'agentpress_capability',
   123→                'post_title' => $cap['title'],
   124→                'post_name' => $cap['slug'],
   125→                'post_status' => 'publish',
   126→                'meta_input' => array(
   127→                    '_capability_slug' => $cap['slug'],
   128→                    '_capability_description' => $cap['description'],
   129→                ),
   130→            ));
   131→        }
   132→    }
   133→}
