   150→/**
   151→ * Plugin activation hook.
   152→ */
   153→function agentpress_activate() {
   154→    // Register CPTs so we can create posts
   155→    agentpress_register_cpts();
   156→
   157→    // Flush rewrite rules
   158→    flush_rewrite_rules();
   159→
   160→    // Seed built-in capabilities
   161→    agentpress_seed_capabilities();
   162→
   163→    // Create default settings
   164→    agentpress_create_default_settings();
   165→}
   166→register_activation_hook(__FILE__, 'agentpress_activate');
   167→
   168→/**
   169→ * Plugin deactivation hook.
   170→ */
   171→function agentpress_deactivate() {
   172→    // Flush rewrite rules on deactivation
   173→    flush_rewrite_rules();
   174→}
   175→register_deactivation_hook(__FILE__, 'agentpress_deactivate');
