   177→/**
   178→ * Autoloader for AgentPress classes.
   179→ *
   180→ * @param string $class Class name to load.
   181→ */
   182→function agentpress_autoloader($class) {
   183→    // Only handle AgentPress namespace
   184→    if (strpos($class, 'AgentPress\\') !== 0) {
   185→        return;
   186→    }
   187→
   188→    // Remove namespace prefix
   189→    $class_name = str_replace('AgentPress\\', '', $class);
   190→
   191→    // Define class file mappings
   192→    $class_map = array(
   193→        'Parser' => 'includes/class-parser.php',
   194→        'Agents' => 'includes/class-agents.php',
   195→        'Logger' => 'includes/class-logger.php',
   196→        'Router' => 'includes/class-router.php',
   197→        'REST_API' => 'includes/class-rest-api.php',
   198→        'Admin' => 'admin/class-admin.php',
   199→        'Content_Writer' => 'includes/agents/class-content-writer.php',
   200→        'Image_Generator' => 'includes/agents/class-image-generator.php',
   201→    );
   202→
   203→    // Handle sub-namespaces like AgentPress\Agents\Content_Writer
   204→    if (strpos($class_name, '\\') !== false) {
   205→        $parts = explode('\\', $class_name);
   206→        $sub_namespace = strtolower($parts[0]);
   207→        $class_name = $parts[1];
   208→
   209→        $file = AGENTPRESS_PLUGIN_DIR . 'includes/' . $sub_namespace . '/class-' . strtolower(str_replace('_', '-', $class_name)) . '.php';
   210→    } else {
   211→        $file = AGENTPRESS_PLUGIN_DIR . (isset($class_map[$class_name]) ? $class_map[$class_name] : '');
   212→    }
   213→
   214→    if (file_exists($file)) {
   215→        require_once $file;
   216→    }
   217→}
   218→spl_autoload_register('agentpress_autoloader');
   219→
   220→/**
   221→ * Initialize core classes on plugins_loaded.
   222→ */
   223→function agentpress_init() {
   224→    // Initialize REST API
   225→    if (class_exists('AgentPress\\REST_API')) {
   226→        new AgentPress\REST_API();
   227→    }
   228→
   229→    // Initialize Admin
   230→    if (is_admin() && class_exists('AgentPress\\Admin')) {
   231→        new AgentPress\Admin();
   232→    }
   233→}
   234→add_action('plugins_loaded', 'agentpress_init');
   235→
   236→/**
   237→ * Register REST API routes.
   238→ */
   239→function agentpress_register_rest_routes() {
   240→    if (class_exists('AgentPress\\REST_API')) {
   241→        AgentPress\REST_API::register_routes();
   242→    }
   243→}
   244→add_action('rest_api_init', 'agentpress_register_rest_routes');
